class Solution:
    def countServers(self, n, logs, x, queries):
        res = []
        for q in queries:
            lo, hi = q - x, q
            seen = set()
            for sid, t in logs:
                if lo <= t <= hi:
                    seen.add(sid)
            res.append(n - len(seen))
        return res

