var countServers = function(n, logs, x, queries) {
    logs = logs.slice().sort((a, b) => a[1] - b[1]);
    const m = queries.length;
    const order = Array.from({length: m}, (_, i) => i).sort((a, b) => queries[a] - queries[b]);
    const ans = new Array(m).fill(0);
    const count = new Map();
    let active = 0;
    let left = 0, right = 0;
    const L = logs.length;
    for (const qi of order) {
        const q = queries[qi];
        const lo = q - x, hi = q;
        while (right < L && logs[right][1] <= hi) {
            const sid = logs[right][0];
            const c = count.get(sid) || 0;
            if (c === 0) active++;
            count.set(sid, c + 1);
            right++;
        }
        while (left < L && logs[left][1] < lo) {
            const sid = logs[left][0];
            const c = count.get(sid) - 1;
            count.set(sid, c);
            if (c === 0) active--;
            left++;
        }
        ans[qi] = n - active;
    }
    return ans;
};
